# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify, Response
import jwt
import requests
import json

app = Flask(__name__)

BACKEND_SERVICES = {
    'users': 'http://localhost:5001',
    'products': 'http://localhost:5002',
    'orders': 'http://localhost:5003'
}

def extract_token():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return None
    
    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return None
    
    return parts[1]

def validate_and_extract_claims(token):
    try:
        claims = jwt.decode(token, options={"verify_signature": False})
        return claims
    except Exception as e:
        return None

def forward_to_backend(service_name, path, claims):
    if service_name not in BACKEND_SERVICES:
        return jsonify({'error': 'Service not found'}), 404
    
    backend_url = BACKEND_SERVICES[service_name] + path
    
    headers = {
        'Content-Type': 'application/json',
        'X-User-Claims': json.dumps(claims)
    }
    
    if request.headers.get('Content-Type'):
        headers['Content-Type'] = request.headers.get('Content-Type')
    
    try:
        if request.method == 'GET':
            response = requests.get(backend_url, headers=headers, params=request.args)
        elif request.method == 'POST':
            response = requests.post(backend_url, headers=headers, json=request.get_json(), params=request.args)
        elif request.method == 'PUT':
            response = requests.put(backend_url, headers=headers, json=request.get_json(), params=request.args)
        elif request.method == 'DELETE':
            response = requests.delete(backend_url, headers=headers, params=request.args)
        elif request.method == 'PATCH':
            response = requests.patch(backend_url, headers=headers, json=request.get_json(), params=request.args)
        else:
            return jsonify({'error': 'Method not allowed'}), 405
        
        return Response(
            response.content,
            status=response.status_code,
            headers=dict(response.headers)
        )
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Backend service unavailable'}), 503

@app.route('/<service_name>/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def gateway(service_name, path):
    token = extract_token()
    
    if not token:
        return jsonify({'error': 'No token provided'}), 401
    
    claims = validate_and_extract_claims(token)
    
    if not claims:
        return jsonify({'error': 'Invalid token'}), 401
    
    return forward_to_backend(service_name, '/' + path, claims)

@app.route('/<service_name>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def gateway_root(service_name):
    token = extract_token()
    
    if not token:
        return jsonify({'error': 'No token provided'}), 401
    
    claims = validate_and_extract_claims(token)
    
    if not claims:
        return jsonify({'error': 'Invalid token'}), 401
    
    return forward_to_backend(service_name, '/', claims)

@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)